import 'package:connectivity_plus/connectivity_plus.dart'; import 'package:injectable/injectable.dart'; import '../utils/app_logger.dart'; @singleton class ConnectivityService { bool _connected = true; bool get isConnected => _connected; Future<void> initialize() async { final r = await Connectivity().checkConnectivity(); _connected = r.first != ConnectivityResult.none; Connectivity().onConnectivityChanged.listen((r) { _connected = r.first != ConnectivityResult.none; AppLogger.info('Connectivity: $_connected'); }); } }